const tutors = variables["de470050-a5d8-43e1-af18-4092d8f7f43d"] || [];
  const selectedSubjects = variables["101cf9d4-e623-4601-a3c0-1fd79c4468fe"] || [];
  const availabilityFilter = variables["719e89f7-52ec-48dd-808e-2e8992f1da38"] || "all";

  // Start with all tutors
  let filteredTutors = [...tutors];

  // Filter by subjects if any are selected
  if (selectedSubjects.length > 0) {
    filteredTutors = filteredTutors.filter(tutor => {
      // Check if any of tutor's subjects match the selected subjects
      return tutor.subjects.some(subject => selectedSubjects.includes(subject));
    });
  }

  // Filter by availability if not set to "all"
  if (availabilityFilter !== "all") {
    filteredTutors = filteredTutors.filter(tutor => {
      return tutor.availability === availabilityFilter;
    });
  }

  return filteredTutors;

